import { useState, type FormEvent } from 'react'
import { Link } from 'react-router-dom'
import { supabase } from '@/lib/supabase'
import { AuthLayout } from '@/components/AuthLayout'
import { Field, Button, FormError } from '@/components/AuthFormPrimitives'

export default function Forgot() {
  const [email, setEmail] = useState('')
  const [error, setError] = useState<string | null>(null)
  const [sent, setSent] = useState(false)
  const [loading, setLoading] = useState(false)

  async function handleSubmit(e: FormEvent) {
    e.preventDefault()
    setError(null)
    setLoading(true)
    const { error } = await supabase.auth.resetPasswordForEmail(email, {
      redirectTo: `${window.location.origin}/magyarul/auth/login`
    })
    setLoading(false)
    if (error) {
      setError(error.message)
      return
    }
    setSent(true)
  }

  return (
    <AuthLayout title="Elfelejtett jelszó" subtitle="Passwort zurücksetzen">
      {sent ? (
        <div style={{ textAlign: 'center' }}>
          <div style={{ fontSize: '2rem', marginBottom: '0.5rem' }}>📬</div>
          <p>
            Wir haben dir einen Link an <b>{email}</b> geschickt. Folge dem Link in
            der Mail, um ein neues Passwort zu setzen.
          </p>
          <Link to="/auth/login" style={{ color: 'var(--green)', display: 'inline-block', marginTop: '1rem' }}>
            Zurück zum Login
          </Link>
        </div>
      ) : (
        <form onSubmit={handleSubmit} noValidate>
          <FormError>{error}</FormError>
          <Field
            label="E-Mail"
            type="email"
            autoComplete="email"
            required
            value={email}
            onChange={(e) => setEmail(e.target.value)}
          />
          <Button type="submit" disabled={loading}>
            {loading ? 'Wird gesendet…' : 'Reset-Link senden'}
          </Button>

          <div style={{ marginTop: '1.2rem', fontSize: '0.85rem', textAlign: 'center' }}>
            <Link to="/auth/login" style={{ color: 'var(--green)' }}>
              Zurück zum Login
            </Link>
          </div>
        </form>
      )}
    </AuthLayout>
  )
}
