import { useEffect } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { useNotificationStore } from '@/store/useNotificationStore'

// Achievement-Toast mit Auto-Dismiss nach 3 s. Queue: nächstes Achievement
// wird gezeigt sobald das aktuelle weg ist.

export function AchievementToast() {
  const queue = useNotificationStore((s) => s.achievementQueue)
  const dismiss = useNotificationStore((s) => s.dismissAchievement)
  const current = queue[0] ?? null

  useEffect(() => {
    if (!current) return
    const t = setTimeout(dismiss, 3000)
    return () => clearTimeout(t)
  }, [current, dismiss])

  return (
    <AnimatePresence>
      {current && (
        <motion.button
          key={current.id}
          initial={{ opacity: 0, y: 30, scale: 0.95 }}
          animate={{ opacity: 1, y: 0, scale: 1 }}
          exit={{ opacity: 0, y: 20, scale: 0.95 }}
          onClick={dismiss}
          style={{
            position: 'fixed',
            bottom: 'calc(80px + env(safe-area-inset-bottom, 0px))',
            left: '50%',
            transform: 'translateX(-50%)',
            zIndex: 80,
            background: 'var(--white)',
            border: '2px solid var(--yellow)',
            color: 'inherit',
            padding: '0.85rem 1.1rem',
            borderRadius: 14,
            boxShadow: '0 8px 24px rgba(200, 160, 0, 0.35)',
            display: 'flex',
            alignItems: 'center',
            gap: 12,
            cursor: 'pointer',
            fontFamily: 'inherit',
            maxWidth: 340,
            width: 'calc(100% - 2rem)'
          }}
        >
          <div style={{ fontSize: '2.1rem', lineHeight: 1 }} aria-hidden="true">{current.icon}</div>
          <div style={{ textAlign: 'left', flex: 1 }}>
            <div style={{ fontSize: '0.7rem', opacity: 0.65, letterSpacing: '0.5px', textTransform: 'uppercase' }}>
              Achievement freigeschaltet
            </div>
            <div style={{ fontFamily: 'Georgia, serif', fontWeight: 700, color: 'var(--red)' }}>{current.title}</div>
            <div style={{ fontSize: '0.75rem', opacity: 0.7 }}>{current.description}</div>
          </div>
          {current.xpReward > 0 && (
            <div style={{ background: 'var(--green)', color: 'var(--cream)', padding: '0.3rem 0.55rem', borderRadius: 999, fontSize: '0.75rem', fontWeight: 700 }}>
              +{current.xpReward}
            </div>
          )}
        </motion.button>
      )}
    </AnimatePresence>
  )
}
