import { useEffect, useState } from 'react'
import { motion, AnimatePresence } from 'framer-motion'

// PWA-Install-Banner laut CLAUDE.md Sprint 9.
//
// Zeigt einen kleinen Banner unter der BottomNav, wenn der Browser einen
// installierbaren `beforeinstallprompt`-Event feuert. Nutzer kann den Banner
// dismissen (1 Woche unterdrückt via localStorage).

type BeforeInstallPromptEvent = Event & {
  prompt: () => Promise<void>
  userChoice: Promise<{ outcome: 'accepted' | 'dismissed' }>
}

const DISMISS_KEY = 'virag_install_dismissed_until'
const DISMISS_DAYS = 7

export function InstallBanner() {
  const [evt, setEvt] = useState<BeforeInstallPromptEvent | null>(null)

  useEffect(() => {
    function onInstallPromptFired(e: Event) {
      e.preventDefault()
      // Wurde kürzlich dismissed?
      const until = parseInt(localStorage.getItem(DISMISS_KEY) || '0', 10)
      if (Date.now() < until) return
      setEvt(e as BeforeInstallPromptEvent)
    }
    window.addEventListener('beforeinstallprompt', onInstallPromptFired)
    return () => window.removeEventListener('beforeinstallprompt', onInstallPromptFired)
  }, [])

  async function handleInstall() {
    if (!evt) return
    await evt.prompt()
    const result = await evt.userChoice
    if (result.outcome === 'dismissed') {
      localStorage.setItem(DISMISS_KEY, String(Date.now() + DISMISS_DAYS * 86400_000))
    }
    setEvt(null)
  }

  function handleDismiss() {
    localStorage.setItem(DISMISS_KEY, String(Date.now() + DISMISS_DAYS * 86400_000))
    setEvt(null)
  }

  return (
    <AnimatePresence>
      {evt && (
        <motion.div
          initial={{ y: 100, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          exit={{ y: 100, opacity: 0 }}
          transition={{ type: 'spring', damping: 22 }}
          style={{
            position: 'fixed',
            bottom: 'calc(80px + env(safe-area-inset-bottom, 0px))',
            left: '50%',
            transform: 'translateX(-50%)',
            zIndex: 70,
            background: 'var(--white)',
            border: '2px solid var(--green)',
            borderRadius: 14,
            padding: '0.85rem 1rem',
            boxShadow: '0 8px 24px rgba(62, 90, 10, 0.25)',
            display: 'flex',
            alignItems: 'center',
            gap: 10,
            maxWidth: 360,
            width: 'calc(100% - 2rem)'
          }}
        >
          <div style={{ fontSize: '1.7rem', lineHeight: 1 }}>📱</div>
          <div style={{ flex: 1, fontSize: '0.85rem' }}>
            <div style={{ fontFamily: 'Georgia, serif', fontWeight: 700, color: 'var(--red)' }}>Virág installieren?</div>
            <div style={{ opacity: 0.7, fontSize: '0.78rem' }}>Schneller starten, offline lernen</div>
          </div>
          <button onClick={handleInstall} style={{ background: 'var(--green)', color: 'var(--cream)', border: 'none', padding: '0.5rem 0.85rem', borderRadius: 8, fontFamily: 'inherit', fontWeight: 700, fontSize: '0.85rem', cursor: 'pointer' }}>
            Installieren
          </button>
          <button onClick={handleDismiss} aria-label="Banner schließen" style={{ background: 'none', border: 'none', fontSize: '1.4rem', opacity: 0.4, cursor: 'pointer', padding: 0, lineHeight: 1 }}>
            ×
          </button>
        </motion.div>
      )}
    </AnimatePresence>
  )
}
