import { useEffect } from 'react'
import { create } from 'zustand'
import { supabase } from '@/lib/supabase'
import { useAuthStore } from './useAuthStore'

// Realtime-Sync auf profiles laut CLAUDE.md Sprint 9.
//
// Idee: Eine globale Subscription auf den eigenen profiles-Row, die jede
// Änderung (XP, Streak, Level, Rang) in den Store schreibt. Komponenten lesen
// daraus statt direkt zu queryen. Das ergibt:
//   - Live-Update der StreakBox / Tagesziel-Bar / Rang-Anzeige
//     wenn der User in einem Spielmodus XP sammelt
//   - Konsistente Werte zwischen Tabs des selben Users
//
// Komponenten, die noch direkt querien (Sprint 4–8 Code), funktionieren
// weiter — sie kriegen jetzt nur zusätzlich Live-Updates wenn sie diesen
// Store nutzen.

export type ProfileSnapshot = {
  display_name: string | null
  username: string | null
  avatar_emoji: string | null
  rank: string | null
  level: number | null
  current_streak: number | null
  longest_streak: number | null
  daily_goal_xp: number | null
  app_xp: Record<string, number> | null
  notifications_enabled: boolean | null
  reminder_time: string | null
}

type ProfileState = {
  profile: ProfileSnapshot | null
  setProfile: (p: ProfileSnapshot | null) => void
  refresh: () => Promise<void>
}

export const useProfileStore = create<ProfileState>((set) => ({
  profile: null,
  setProfile: (profile) => set({ profile }),
  refresh: async () => {
    const { data: { user } } = await supabase.auth.getUser()
    if (!user) { set({ profile: null }); return }
    const { data } = await supabase
      .from('profiles')
      .select('display_name, username, avatar_emoji, rank, level, current_streak, longest_streak, daily_goal_xp, app_xp, notifications_enabled, reminder_time')
      .eq('id', user.id)
      .single()
    set({ profile: data as ProfileSnapshot | null })
  }
}))

/**
 * Hook für die App-Root: startet die Realtime-Subscription auf das eigene
 * Profile-Row sobald eine Session existiert. Updates landen im Store.
 */
export function useProfileRealtime(): void {
  const { user } = useAuthStore()

  useEffect(() => {
    if (!user) {
      useProfileStore.getState().setProfile(null)
      return
    }

    // Initial laden
    void useProfileStore.getState().refresh()

    // Realtime-Subscription
    const channel = supabase
      .channel(`profile-${user.id}`)
      .on(
        'postgres_changes',
        {
          event: 'UPDATE',
          schema: 'public',
          table: 'profiles',
          filter: `id=eq.${user.id}`
        },
        (payload) => {
          useProfileStore.getState().setProfile(payload.new as ProfileSnapshot)
        }
      )
      .subscribe()

    return () => {
      void supabase.removeChannel(channel)
    }
  }, [user])
}
