// Header-Streifen laut CLAUDE.md §5: 5px hoch, gelb/orange repeating-gradient,
// platziert unter dem FolkDivider auf jedem Screen.
// Gradient kommt aus colors.css (--header-stripe), keine Hex-Literale hier.

type Props = {
  height?: number
  className?: string
}

export function HeaderStripe({ height = 5, className }: Props) {
  return (
    <div
      className={className}
      role="presentation"
      aria-hidden="true"
      style={{
        height,
        width: '100%',
        background: 'var(--header-stripe)'
      }}
    />
  )
}
