import { createClient } from '@supabase/supabase-js'

const url = import.meta.env.VITE_SUPABASE_URL
const anonKey = import.meta.env.VITE_SUPABASE_ANON_KEY

if (!url || !anonKey) {
  throw new Error('VITE_SUPABASE_URL und VITE_SUPABASE_ANON_KEY müssen in .env.local gesetzt sein')
}

// Same-Origin Setup (nephron.at/magyarul/) — kein cookieOptions.domain nötig.
// Falls SSO mit zukünftigen Subdomain-Apps gebraucht wird, hier auf '.nephron.at' erweitern.
export const supabase = createClient(url, anonKey, {
  auth: {
    storage: typeof window !== 'undefined' ? window.localStorage : undefined,
    autoRefreshToken: true,
    persistSession: true,
    detectSessionInUrl: true
  }
})
