import { useState, type FormEvent } from 'react'
import { Link, useNavigate } from 'react-router-dom'
import { supabase } from '@/lib/supabase'
import { AuthLayout } from '@/components/AuthLayout'
import { Field, Button, FormError } from '@/components/AuthFormPrimitives'

export default function Signup() {
  const [email, setEmail] = useState('')
  const [password, setPassword] = useState('')
  const [displayName, setDisplayName] = useState('')
  const [error, setError] = useState<string | null>(null)
  const [info, setInfo] = useState<string | null>(null)
  const [loading, setLoading] = useState(false)
  const navigate = useNavigate()

  async function handleSubmit(e: FormEvent) {
    e.preventDefault()
    setError(null)
    setInfo(null)

    if (password.length < 8) {
      setError('Passwort muss mindestens 8 Zeichen haben.')
      return
    }

    setLoading(true)
    const { data, error } = await supabase.auth.signUp({
      email,
      password,
      options: {
        data: { display_name: displayName || email.split('@')[0] },
        // Weiterleitung nach E-Mail-Bestätigung direkt ins Onboarding
        emailRedirectTo: `${window.location.origin}/magyarul/onboarding`
      }
    })
    setLoading(false)

    if (error) {
      setError(translateError(error.message))
      return
    }

    // Wenn Email-Confirmation aktiv ist, hat data.session noch keinen Token.
    if (!data.session) {
      setInfo(
        'Wir haben dir eine Bestätigungs-Mail geschickt. Klick auf den Link, dann landest du im Onboarding.'
      )
      return
    }
    navigate('/onboarding', { replace: true })
  }

  return (
    <AuthLayout title="Új fiók" subtitle="Account erstellen">
      <form onSubmit={handleSubmit} noValidate>
        <FormError>{error}</FormError>
        {info && (
          <div
            role="status"
            style={{
              padding: '0.7rem 0.9rem',
              background: 'rgba(62, 90, 10, 0.08)',
              border: '1px solid var(--green)',
              borderRadius: 8,
              color: 'var(--green)',
              fontSize: '0.85rem',
              marginBottom: '0.9rem'
            }}
          >
            {info}
          </div>
        )}
        <Field
          label="Anzeigename (optional)"
          type="text"
          autoComplete="nickname"
          value={displayName}
          onChange={(e) => setDisplayName(e.target.value)}
          placeholder="z.B. Peer"
        />
        <Field
          label="E-Mail"
          type="email"
          autoComplete="email"
          required
          value={email}
          onChange={(e) => setEmail(e.target.value)}
        />
        <Field
          label="Passwort (min. 8 Zeichen)"
          type="password"
          autoComplete="new-password"
          required
          minLength={8}
          value={password}
          onChange={(e) => setPassword(e.target.value)}
        />
        <Button type="submit" disabled={loading}>
          {loading ? 'Account wird erstellt…' : 'Account erstellen'}
        </Button>

        <div
          style={{
            marginTop: '1.2rem',
            fontSize: '0.85rem',
            textAlign: 'center'
          }}
        >
          <Link to="/auth/login" style={{ color: 'var(--green)' }}>
            Schon einen Account? Einloggen
          </Link>
        </div>
      </form>
    </AuthLayout>
  )
}

function translateError(msg: string): string {
  if (msg.toLowerCase().includes('already registered')) return 'Diese E-Mail ist schon registriert. Bitte logg dich ein.'
  if (msg.toLowerCase().includes('weak password')) return 'Passwort ist zu schwach.'
  if (msg.toLowerCase().includes('invalid email')) return 'Ungültige E-Mail-Adresse.'
  if (msg.toLowerCase().includes('rate limit')) return 'Zu viele Versuche — bitte kurz warten.'
  return msg
}
