import { create } from 'zustand'

// Zentrale Notification-Queue für Level-Ups + Achievement-Unlocks.
// Wird von lib/xp.ts und lib/achievements.ts gefüllt, von <NotificationCenter />
// gerendert.

export type LevelUpEvent = {
  id: number
  fromLevel: number
  toLevel: number
  rankHu: string
  rankDe: string
}

export type AchievementEvent = {
  id: number
  code: string
  title: string
  description: string
  icon: string
  xpReward: number
}

type NotificationState = {
  levelUp: LevelUpEvent | null
  achievementQueue: AchievementEvent[]
  pushLevelUp: (e: Omit<LevelUpEvent, 'id'>) => void
  pushAchievement: (e: Omit<AchievementEvent, 'id'>) => void
  dismissLevelUp: () => void
  dismissAchievement: () => void
}

let counter = 1
const nextId = () => counter++

export const useNotificationStore = create<NotificationState>((set) => ({
  levelUp: null,
  achievementQueue: [],
  pushLevelUp: (e) => set({ levelUp: { ...e, id: nextId() } }),
  pushAchievement: (e) =>
    set((s) => ({ achievementQueue: [...s.achievementQueue, { ...e, id: nextId() }] })),
  dismissLevelUp: () => set({ levelUp: null }),
  dismissAchievement: () =>
    set((s) => ({ achievementQueue: s.achievementQueue.slice(1) }))
}))
