import { useState, type FormEvent } from 'react'
import { Link, useNavigate } from 'react-router-dom'
import { supabase } from '@/lib/supabase'
import { AuthLayout } from '@/components/AuthLayout'
import { Field, Button, FormError } from '@/components/AuthFormPrimitives'

export default function Login() {
  const [email, setEmail] = useState('')
  const [password, setPassword] = useState('')
  const [error, setError] = useState<string | null>(null)
  const [loading, setLoading] = useState(false)
  const navigate = useNavigate()

  async function handleSubmit(e: FormEvent) {
    e.preventDefault()
    setError(null)
    setLoading(true)
    const { error } = await supabase.auth.signInWithPassword({ email, password })
    setLoading(false)
    if (error) {
      setError(translateError(error.message))
      return
    }
    navigate('/home', { replace: true })
  }

  // Google OAuth — nur sichtbar, wenn VITE_GOOGLE_OAUTH_ENABLED=true UND der
  // Provider im Supabase-Dashboard aktiviert ist. Default: aus.
  const googleEnabled = import.meta.env.VITE_GOOGLE_OAUTH_ENABLED === 'true'

  async function handleGoogle() {
    setError(null)
    const { error } = await supabase.auth.signInWithOAuth({
      provider: 'google',
      options: { redirectTo: `${window.location.origin}/magyarul/home` }
    })
    if (error) setError(translateError(error.message))
  }

  return (
    <AuthLayout title="Bejelentkezés" subtitle="Anmelden bei Virág">
      <form onSubmit={handleSubmit} noValidate>
        <FormError>{error}</FormError>
        <Field
          label="E-Mail"
          type="email"
          autoComplete="email"
          required
          value={email}
          onChange={(e) => setEmail(e.target.value)}
        />
        <Field
          label="Passwort"
          type="password"
          autoComplete="current-password"
          required
          value={password}
          onChange={(e) => setPassword(e.target.value)}
        />
        <Button type="submit" disabled={loading}>
          {loading ? 'Anmeldung läuft…' : 'Einloggen'}
        </Button>

        {googleEnabled && (
          <>
            <div
              style={{
                textAlign: 'center',
                margin: '1.2rem 0 0.8rem',
                fontSize: '0.8rem',
                opacity: 0.5
              }}
            >
              oder
            </div>

            <Button type="button" variant="ghost" onClick={handleGoogle}>
              🔑 Mit Google anmelden
            </Button>
          </>
        )}

        <div
          style={{
            display: 'flex',
            justifyContent: 'space-between',
            marginTop: '1.2rem',
            fontSize: '0.85rem'
          }}
        >
          <Link to="/auth/forgot" style={{ color: 'var(--green)' }}>
            Passwort vergessen?
          </Link>
          <Link to="/auth/signup" style={{ color: 'var(--green)' }}>
            Account erstellen
          </Link>
        </div>
      </form>
    </AuthLayout>
  )
}

function translateError(msg: string): string {
  // Supabase liefert englische Fehlermeldungen — wir zeigen deutsche.
  if (msg.includes('Invalid login credentials')) return 'E-Mail oder Passwort falsch.'
  if (msg.includes('Email not confirmed')) return 'Bitte bestätige zuerst deine E-Mail-Adresse.'
  if (msg.includes('rate limit')) return 'Zu viele Versuche — bitte kurz warten.'
  return msg
}
