// Kalocsa-Folk-Trennlinie — exakt nach CLAUDE.md §5.
// 38px hoch, cremefarbener Hintergrund, geschwungene Wellenlinie mit
// alternierenden Blüten (rot/orange + goldener Innenpunkt) und Blättern.
//
// SVG-viewBox ist breit gewählt (1000) — preserveAspectRatio="none" streckt
// die Linie auf jede Container-Breite, ohne dass die Höhe leidet.

type Props = {
  className?: string
  height?: number
}

export function FolkDivider({ className, height = 38 }: Props) {
  // Wellenpunkte (x-Koordinaten der Blüten) — gleichmäßig verteilt
  const flowerXs = [80, 220, 360, 500, 640, 780, 920]

  return (
    <svg
      className={className}
      width="100%"
      height={height}
      viewBox="0 0 1000 38"
      preserveAspectRatio="none"
      role="presentation"
      aria-hidden="true"
      style={{ display: 'block', background: 'var(--cream)' }}
    >
      {/* Wellenlinie blattgrün */}
      <path
        d="M0 19 Q 80 4, 160 19 T 320 19 T 480 19 T 640 19 T 800 19 T 960 19 L 1000 19"
        fill="none"
        stroke="var(--green)"
        strokeWidth={1.8}
        vectorEffect="non-scaling-stroke"
      />

      {/* Blätter zwischen den Blüten — alternierend oben/unten */}
      {flowerXs.slice(0, -1).map((x, i) => {
        const next = flowerXs[i + 1]
        const cx = (x + next) / 2
        const isUp = i % 2 === 0
        const cy = isUp ? 10 : 28
        const rotate = isUp ? -30 : 30
        const fill = isUp ? 'var(--green)' : 'var(--lg)'
        return (
          <ellipse
            key={`leaf-${i}`}
            cx={cx}
            cy={cy}
            rx={6}
            ry={2.5}
            fill={fill}
            transform={`rotate(${rotate} ${cx} ${cy})`}
          />
        )
      })}

      {/* Blüten — alternierend rot (r=6) und orange (r=5) mit goldenem Innenpunkt */}
      {flowerXs.map((x, i) => {
        const isRed = i % 2 === 0
        const r = isRed ? 6 : 5
        const innerR = isRed ? 2.8 : 2.4
        const outerFill = isRed ? 'var(--red)' : 'var(--orange)'
        return (
          <g key={`flower-${i}`}>
            <circle cx={x} cy={19} r={r} fill={outerFill} />
            <circle cx={x} cy={19} r={innerR} fill="var(--yellow)" />
          </g>
        )
      })}
    </svg>
  )
}
