import { lazy, Suspense } from 'react'
import { Navigate, Route, Routes } from 'react-router-dom'
import { useAuthStore } from './store/useAuthStore'
import { useProfileRealtime } from './store/useProfileStore'
import { ProtectedRoute } from './components/ProtectedRoute'
import { NotificationCenter } from './components/NotificationCenter'
import { InstallBanner } from './components/InstallBanner'
import { Header } from './components/Header'

// Eager-loaded: Splash + Auth-Screens (kleiner First-Paint-Pfad)
import Splash from './screens/Splash'
import Login from './screens/auth/Login'
import Signup from './screens/auth/Signup'
import Forgot from './screens/auth/Forgot'

// Lazy-loaded: alle Game-Screens + Hubs + Profile/Stats.
// Sparen den initialen Bundle (Framer Motion bleibt bis Game/Onboarding-Click weg).
const Demo         = lazy(() => import('./screens/Demo'))
const Onboarding   = lazy(() => import('./screens/Onboarding'))
const Home         = lazy(() => import('./screens/Home'))
const Learn        = lazy(() => import('./screens/Learn'))
const Stats        = lazy(() => import('./screens/Stats'))
const Profile      = lazy(() => import('./screens/Profile'))
const DeleteAccount = lazy(() => import('./screens/DeleteAccount'))
const Flashcards   = lazy(() => import('./screens/learn/Flashcards'))
const Matching     = lazy(() => import('./screens/learn/Matching'))
const Ordering     = lazy(() => import('./screens/learn/Ordering'))
const Speedround   = lazy(() => import('./screens/learn/Speedround'))
const Quiz         = lazy(() => import('./screens/learn/Quiz'))
const VocabTrainer = lazy(() => import('./screens/learn/VocabTrainer'))
const VerbTrainer  = lazy(() => import('./screens/learn/VerbTrainer'))
const VerbConjugate = lazy(() => import('./screens/learn/verb/Conjugate'))
const VerbMC      = lazy(() => import('./screens/learn/verb/MultipleChoice'))
const VerbReverse = lazy(() => import('./screens/learn/verb/Reverse'))
const VerbTable   = lazy(() => import('./screens/learn/verb/TableFill'))
const VerbCloze   = lazy(() => import('./screens/learn/verb/Cloze'))
const SynonymMatch = lazy(() => import('./screens/learn/SynonymMatch'))

// Splash für Suspense-Fallback während Lazy-Chunks laden — gleicher Folk-Look
// wie der echte Splash-Screen, damit der Übergang nicht reißt.
function LoadingFallback() {
  return (
    <div style={{ minHeight: '100vh', background: 'var(--cream)', display: 'flex', flexDirection: 'column' }}>
      <Header />
      <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', opacity: 0.45, fontSize: '1.5rem' }}>
        🌺
      </div>
    </div>
  )
}

export default function App() {
  useProfileRealtime()
  return (
    <>
      <NotificationCenter />
      <InstallBanner />
      <Suspense fallback={<LoadingFallback />}>
        <Routes>
          <Route path="/" element={<RootRedirect />} />
          <Route path="/splash" element={<Splash />} />
          <Route path="/demo" element={<Demo />} />

          <Route path="/auth/login" element={<Login />} />
          <Route path="/auth/signup" element={<Signup />} />
          <Route path="/auth/forgot" element={<Forgot />} />

          <Route path="/onboarding" element={<ProtectedRoute><Onboarding /></ProtectedRoute>} />
          <Route path="/home"       element={<ProtectedRoute><Home /></ProtectedRoute>} />
          <Route path="/learn"      element={<ProtectedRoute><Learn /></ProtectedRoute>} />
          <Route path="/stats"      element={<ProtectedRoute><Stats /></ProtectedRoute>} />
          <Route path="/profile"    element={<ProtectedRoute><Profile /></ProtectedRoute>} />

          <Route path="/learn/medical/flashcards"             element={<ProtectedRoute><Flashcards /></ProtectedRoute>} />
          <Route path="/learn/medical/matching"               element={<ProtectedRoute><Matching /></ProtectedRoute>} />
          <Route path="/learn/medical/ordering"               element={<ProtectedRoute><Ordering /></ProtectedRoute>} />
          <Route path="/learn/medical/speedround"             element={<ProtectedRoute><Speedround /></ProtectedRoute>} />
          <Route path="/learn/medical/quiz"                   element={<ProtectedRoute><Quiz /></ProtectedRoute>} />
          <Route path="/learn/medical/vocab-trainer"          element={<ProtectedRoute><VocabTrainer /></ProtectedRoute>} />
          <Route path="/learn/medical/verb-trainer"           element={<ProtectedRoute><VerbTrainer /></ProtectedRoute>} />
          <Route path="/learn/medical/verb-trainer/conjugate" element={<ProtectedRoute><VerbConjugate /></ProtectedRoute>} />
          <Route path="/learn/medical/verb-trainer/mc"        element={<ProtectedRoute><VerbMC /></ProtectedRoute>} />
          <Route path="/learn/medical/verb-trainer/reverse"   element={<ProtectedRoute><VerbReverse /></ProtectedRoute>} />
          <Route path="/learn/medical/verb-trainer/table"     element={<ProtectedRoute><VerbTable /></ProtectedRoute>} />
          <Route path="/learn/medical/verb-trainer/cloze"     element={<ProtectedRoute><VerbCloze /></ProtectedRoute>} />
          <Route path="/learn/medical/synonym-match"          element={<ProtectedRoute><SynonymMatch /></ProtectedRoute>} />
          <Route path="/profile/delete-account"               element={<ProtectedRoute><DeleteAccount /></ProtectedRoute>} />

          <Route path="*" element={<Navigate to="/" replace />} />
        </Routes>
      </Suspense>
    </>
  )
}

function RootRedirect() {
  const { session, hydrated } = useAuthStore()
  if (!hydrated) return <Splash />
  return <Navigate to={session ? '/home' : '/auth/login'} replace />
}
