import { useEffect } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { useNotificationStore } from '@/store/useNotificationStore'
import { fireFlowerConfetti } from '@/lib/confetti'

// Vollbild-Overlay bei Level-Up mit 🌺-Konfetti laut CLAUDE.md §8.

export function LevelUpOverlay() {
  const event = useNotificationStore((s) => s.levelUp)
  const dismiss = useNotificationStore((s) => s.dismissLevelUp)

  useEffect(() => {
    if (!event) return
    fireFlowerConfetti()
  }, [event])

  return (
    <AnimatePresence>
      {event && (
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          onClick={dismiss}
          style={{
            position: 'fixed',
            inset: 0,
            background: 'rgba(0, 0, 0, 0.55)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            zIndex: 100,
            padding: '1.5rem',
            cursor: 'pointer'
          }}
        >
          <motion.div
            initial={{ scale: 0.7, opacity: 0 }}
            animate={{ scale: 1, opacity: 1 }}
            transition={{ type: 'spring', stiffness: 200, damping: 18 }}
            onClick={(e) => e.stopPropagation()}
            style={{
              background: 'var(--cream)',
              border: '4px solid var(--red)',
              borderRadius: 24,
              padding: '2rem 1.8rem',
              maxWidth: 380,
              width: '100%',
              textAlign: 'center',
              boxShadow: '0 20px 60px rgba(0,0,0,0.3)'
            }}
          >
            <div style={{ fontSize: '4rem', marginBottom: '0.4rem' }}>🌺</div>
            <div style={{ fontSize: '0.85rem', opacity: 0.65, letterSpacing: '1px', textTransform: 'uppercase' }}>
              Level-Up!
            </div>
            <div className="app-name" style={{ fontSize: '3.5rem', color: 'var(--red)', margin: '0.4rem 0' }}>
              {event.toLevel}
            </div>
            <div style={{ fontFamily: 'Georgia, serif', fontSize: '1.4rem', color: 'var(--green)', fontWeight: 700 }}>
              {event.rankHu}
            </div>
            <div style={{ opacity: 0.65, fontSize: '0.9rem', marginTop: 2 }}>
              {event.rankDe}
            </div>
            <div style={{ marginTop: '1.5rem', fontSize: '0.85rem', opacity: 0.55 }}>
              tippen zum Schließen
            </div>
          </motion.div>
        </motion.div>
      )}
    </AnimatePresence>
  )
}
