import { supabase } from './supabase'
import { useNotificationStore } from '@/store/useNotificationStore'

// Zentraler Achievement-Engine laut CLAUDE.md §8 + 05_achievements.sql.
//
// API:
//   - unlockAchievement(code) — direkter Unlock (z.B. first_flower nach Onboarding)
//   - checkAchievementsAfterXp(userId, source) — wird von awardXp() automatisch
//     aufgerufen und prüft die "lazy"-Achievements (cards_50, streak_*, ...)
//   - notifyManualAchievement(code) — für Modus-spezifische Triggers
//     (perfect_quiz nach 10/10 Quiz, speedrun_50 nach 50 in Speedround)
//
// Idempotent — schon unlocked = skip.

type AchievementDef = {
  id: number
  code: string
  title_de: string
  description_de: string | null
  icon_emoji: string | null
  xp_reward: number
}

let cachedDefs: Map<string, AchievementDef> | null = null
let cachedUnlocked: Set<string> | null = null
let currentUserId: string | null = null

async function loadDefs(): Promise<Map<string, AchievementDef>> {
  if (cachedDefs) return cachedDefs
  const { data } = await supabase
    .from('achievements')
    .select('id, code, title_de, description_de, icon_emoji, xp_reward')
  cachedDefs = new Map<string, AchievementDef>()
  for (const r of (data ?? []) as AchievementDef[]) cachedDefs.set(r.code, r)
  return cachedDefs
}

async function loadUnlocked(userId: string): Promise<Set<string>> {
  if (cachedUnlocked && currentUserId === userId) return cachedUnlocked
  const { data } = await supabase
    .from('user_achievements')
    .select('achievement_id, achievements:achievement_id(code)')
    .eq('user_id', userId)
  cachedUnlocked = new Set<string>()
  for (const r of (data ?? []) as Array<{ achievements: { code: string } | { code: string }[] | null }>) {
    const a = Array.isArray(r.achievements) ? r.achievements[0] : r.achievements
    if (a?.code) cachedUnlocked.add(a.code)
  }
  currentUserId = userId
  return cachedUnlocked
}

export function clearAchievementCache() {
  cachedDefs = null
  cachedUnlocked = null
  currentUserId = null
}

/** Schaltet einen einzelnen Achievement frei (idempotent). Pusht Toast bei Erfolg. */
export async function unlockAchievement(code: string): Promise<void> {
  const { data: { user } } = await supabase.auth.getUser()
  if (!user) return
  const defs = await loadDefs()
  const def = defs.get(code)
  if (!def) return
  const unlocked = await loadUnlocked(user.id)
  if (unlocked.has(code)) return

  // INSERT in user_achievements
  const { error } = await supabase
    .from('user_achievements')
    .insert({ user_id: user.id, achievement_id: def.id })
  if (error && !/duplicate|conflict/i.test(error.message)) return

  unlocked.add(code)

  // XP-Reward separat insert + JSONB-update (vermeidet rekursive awardXp call,
  // weil das wieder Level-Up + Achievement-Check triggern würde — endlos)
  if (def.xp_reward > 0) {
    const { data: profile } = await supabase
      .from('profiles')
      .select('app_xp')
      .eq('id', user.id)
      .single()
    const cur = ((profile?.app_xp as Record<string, number> | null) ?? {})
    const next = { ...cur, virag: (cur.virag ?? 0) + def.xp_reward }
    await Promise.all([
      supabase.from('xp_events').insert({
        user_id: user.id, app: 'virag', mode: 'meta',
        xp_amount: def.xp_reward, source: `achievement:${code}`
      }),
      supabase.from('profiles').update({ app_xp: next }).eq('id', user.id)
    ])
  }

  // Toast
  useNotificationStore.getState().pushAchievement({
    code,
    title: def.title_de,
    description: def.description_de ?? '',
    icon: def.icon_emoji ?? '🏆',
    xpReward: def.xp_reward
  })
}

/**
 * Lazy check after XP-event: prüft die Achievements deren Bedingungen sich
 * mit XP/Card-Reviews/Streak verändern. Manuelle Achievements
 * (perfect_quiz, speedrun_50) sind hier NICHT — die müssen die jeweiligen
 * Modus-Screens via unlockAchievement() selbst triggern.
 */
export async function checkAchievementsAfterXp(userId: string, source: string): Promise<void> {
  const unlocked = await loadUnlocked(userId)

  // Streak-Achievements: lese current_streak
  if (
    !unlocked.has('streak_3') ||
    !unlocked.has('streak_7') ||
    !unlocked.has('streak_30') ||
    !unlocked.has('streak_100')
  ) {
    const { data: p } = await supabase
      .from('profiles').select('current_streak').eq('id', userId).single()
    const s = (p?.current_streak as number) ?? 0
    if (s >= 3   && !unlocked.has('streak_3'))   await unlockAchievement('streak_3')
    if (s >= 7   && !unlocked.has('streak_7'))   await unlockAchievement('streak_7')
    if (s >= 30  && !unlocked.has('streak_30'))  await unlockAchievement('streak_30')
    if (s >= 100 && !unlocked.has('streak_100')) await unlockAchievement('streak_100')
  }

  // Cards-Achievements: count srs_medical mit repetitions >= 3
  if (!unlocked.has('cards_50') || !unlocked.has('cards_500') || !unlocked.has('medical_starter')) {
    const { count: total } = await supabase
      .from('srs_medical')
      .select('id', { count: 'exact', head: true })
      .eq('user_id', userId)
    const { count: mastered } = await supabase
      .from('srs_medical')
      .select('id', { count: 'exact', head: true })
      .eq('user_id', userId)
      .gte('repetitions', 3)
    if ((total ?? 0) >= 10  && !unlocked.has('medical_starter')) await unlockAchievement('medical_starter')
    if ((mastered ?? 0) >= 50  && !unlocked.has('cards_50'))     await unlockAchievement('cards_50')
    if ((mastered ?? 0) >= 500 && !unlocked.has('cards_500'))    await unlockAchievement('cards_500')
  }

  // First Typing: source startet mit "vocab_trainer_exact" oder "verb_conjugate_exact"
  if (!unlocked.has('first_typing') && /^(vocab_trainer_exact|verb_conjugate_exact|verb_cloze_exact)$/.test(source)) {
    await unlockAchievement('first_typing')
  }

  // Production-Mastery 25
  if (!unlocked.has('production_25')) {
    const { count: prod } = await supabase
      .from('srs_medical')
      .select('id', { count: 'exact', head: true })
      .eq('user_id', userId)
      .not('production_mastered_at', 'is', null)
    if ((prod ?? 0) >= 25) await unlockAchievement('production_25')
  }

  // Ikes-Master: 5 ikes-Verben mit mastered_at im present_indefinite
  if (!unlocked.has('ikes_master')) {
    const { data: ikesProgress } = await supabase
      .from('verb_progress_medical')
      .select('mastery, verbs_medical:verb_id(is_ikes)')
      .eq('user_id', userId)
    type Row = { mastery: { present_indefinite?: { mastered_at?: string | null } } | null; verbs_medical: { is_ikes: boolean } | { is_ikes: boolean }[] | null }
    const masteredIkes = ((ikesProgress ?? []) as Row[]).filter((r) => {
      const v = Array.isArray(r.verbs_medical) ? r.verbs_medical[0] : r.verbs_medical
      return v?.is_ikes && r.mastery?.present_indefinite?.mastered_at
    })
    if (masteredIkes.length >= 5) await unlockAchievement('ikes_master')
  }
}
